import React, { useEffect, useState } from 'react';
import axios from 'axios';
import './App.css';

const emptyForm = {
  fullName: '',
  email: '',
  mobileNumber: '',
  department: '',
  designation: '',
  joiningDate: '',
  status: 'Active'
};

const App = () => {
  const [stats, setStats] = useState({ totalEmployees: 0, activeEmployees: 0, inactiveEmployees: 0 });
  const [employees, setEmployees] = useState([]);
  const [form, setForm] = useState(emptyForm);
  const [editingId, setEditingId] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
 const [departmentFilter, setDepartmentFilter] = useState("");
const [statusFilter, setStatusFilter] = useState("");
  const fetchData = async () => {
    const [statsResponse, employeesResponse] = await Promise.all([
      axios.get('http://localhost:5000/api/employees/dashboard'),
      axios.get('http://localhost:5000/api/employees')
    ]);
    setStats(statsResponse.data);
    setEmployees(employeesResponse.data);
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleChange = (event) => {
    const { name, value } = event.target;
    setForm((current) => ({ ...current, [name]: value }));
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    if (editingId) {
      await axios.put(`http://localhost:5000/api/employees/${editingId}`, form);
    } else {
      await axios.post('http://localhost:5000/api/employees', form);
    }
    setForm(emptyForm);
    setEditingId(null);
    fetchData();
  };

  const handleEdit = (employee) => {
    setEditingId(employee.id);
    setForm(employee);
  };

  const handleDelete = async (id) => {
    await axios.delete(`http://localhost:5000/api/employees/${id}`);
    fetchData();
  };

  return (
    <div className="container">
      <div className="header">
        <div>
          <h1>Employee Management System</h1>
          <p style={{ color: '#475569', margin: '4px 0 0' }}>Manage employees with a complete CRUD workflow.</p>
        </div>
      </div>

      <div className="stats-grid">
        <div className="card">
          <strong>Total Employees</strong>
          <div className="stat-value">{stats.totalEmployees}</div>
        </div>
        <div className="card">
          <strong>Active Employees</strong>
          <div className="stat-value">{stats.activeEmployees}</div>
        </div>
        <div className="card">
          <strong>Inactive Employees</strong>
          <div className="stat-value">{stats.inactiveEmployees}</div>
        </div>
      </div>

      <div className="card" style={{ marginBottom: '24px' }}>
        <h2 style={{ marginTop: 0 }}>{editingId ? 'Edit Employee' : 'Add Employee'}</h2>
        <form onSubmit={handleSubmit}>
          <div className="form-grid">
            <label>
              Full Name
              <input name="fullName" value={form.fullName} onChange={handleChange} required />
            </label>
            <label>
              Email
              <input name="email" type="email" value={form.email} onChange={handleChange} required />
            </label>
            <label>
              Mobile Number
              <input name="mobileNumber" value={form.mobileNumber} onChange={handleChange} required />
            </label>
            <label>
              Department
              <input name="department" value={form.department} onChange={handleChange} required />
            </label>
            <label>
              Designation
              <input name="designation" value={form.designation} onChange={handleChange} required />
            </label>
            <label>
              Joining Date
              <input name="joiningDate" type="date" value={form.joiningDate} onChange={handleChange} required />
            </label>
            <label>
              Status
              <select name="status" value={form.status} onChange={handleChange}>
                <option value="Active">Active</option>
                <option value="Inactive">Inactive</option>
              </select>
            </label>
          </div>
          <div style={{ display: 'flex', gap: '10px', marginTop: '12px' }}>
            <button type="submit">{editingId ? 'Update Employee' : 'Save Employee'}</button>
            {editingId ? (
              <button type="button" className="secondary" onClick={() => { setForm(emptyForm); setEditingId(null); }}>
                Cancel
              </button>
            ) : null}
          </div>
        </form>
      </div>

      <div className="card">
        <h2 style={{ marginTop: 0 }}>Employee List</h2>
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Name</th>
                <th>Department</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {employees.map((employee) => (
                <tr key={employee.id}>
                  <td>{employee.fullName}</td>
                  <td>{employee.department}</td>
                  <td>{employee.status}</td>
                  <td>
                    <div className="actions">
                      <button type="button" onClick={() => handleEdit(employee)}>Edit</button>
                      <button type="button" className="danger" onClick={() => handleDelete(employee.id)}>Delete</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default App;
